        const menu = menuOf(actionsOf(results, 'a.txt'));

        // Far beyond the viewport — would overflow off-screen without clamping.
        openViaContext(row, 99999, 99999);

        const left = px(menu.style.left);
        const top = px(menu.style.top);
        const rect = menu.getBoundingClientRect();

        // The raw coords were NOT used verbatim.
        expect(left).toBeLessThan(99999);
        expect(top).toBeLessThan(99999);
        // Clamped exactly to the largest x/y that keeps the menu inside, with a
        // 4px right/bottom margin (width/height subtracted so the far edge fits).
        expect(left).toBe(window.innerWidth - rect.width - 4);
        expect(top).toBe(window.innerHeight - rect.height - 4);
        expect(left).toBe(expectedClampX(menu, 99999));
        expect(top).toBe(expectedClampY(menu, 99999));
        // Menu box stays entirely within the viewport.
        expect(left).toBeGreaterThanOrEqual(4);
        expect(top).toBeGreaterThanOrEqual(4);
        expect(left + rect.width).toBeLessThanOrEqual(window.innerWidth);
        expect(top + rect.height).toBeLessThanOrEqual(window.innerHeight);
