/* =====================================================================
 * Trigger accessible name — the ⋮ trigger's aria-label must be unique per
 * row by including the entry it acts on.
 *
 * Previously every row's trigger carried the identical aria-label
 * "Actions", so a screen-reader user navigating the table by name heard
 * "Actions, button" for every row and could not tell which file/folder's
 * actions it controls. The accessible name must now be "Actions for <name>"
 * so each trigger is distinguishable. Only the aria-label changes; the
 * visible ⋮ glyph and the other trigger attributes (type, aria-haspopup,
 * aria-expanded) are unchanged — the latter are pinned by the "structure"
 * suite above and re-checked below as a regression guard.
 * ===================================================================== */
describe('trigger accessible name — aria-label includes the entry it acts on', () => {
  const f1 = fileEntry({
    name: 'report.pdf',
    path: 'docs/report.pdf',
    isDirectory: false,
    size: 11,
  });
  const f2 = fileEntry({
    name: 'data.csv',
    path: 'docs/data.csv',
    isDirectory: false,
    size: 22,
  });
  const folder = fileEntry({ name: 'archive', path: 'docs/archive', isDirectory: true });

  it('includes the file name in the aria-label', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [f1] }));

    expect(menuBtnOf(actionsOf(results, 'report.pdf')).getAttribute('aria-label')).toBe(
      'Actions for report.pdf',
    );
  });

  it('includes the folder name in the aria-label', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [folder] }));

    expect(menuBtnOf(actionsOf(results, 'archive')).getAttribute('aria-label')).toBe(
      'Actions for archive',
    );
  });

  it('gives every row a distinct aria-label (no longer a generic "Actions, button" per row)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [f1, f2, folder] }));

    const pdfLabel = menuBtnOf(actionsOf(results, 'report.pdf')).getAttribute('aria-label');
    const csvLabel = menuBtnOf(actionsOf(results, 'data.csv')).getAttribute('aria-label');
    const dirLabel = menuBtnOf(actionsOf(results, 'archive')).getAttribute('aria-label');

    expect(pdfLabel).toBe('Actions for report.pdf');
    expect(csvLabel).toBe('Actions for data.csv');
    expect(dirLabel).toBe('Actions for archive');
    // The whole point of the fix: the three triggers are no longer identical.
    expect(new Set([pdfLabel, csvLabel, dirLabel]).size).toBe(3);
  });

  it('starts with the "Actions for " prefix so the role is still announced', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [f1] }));

    const label = menuBtnOf(actionsOf(results, 'report.pdf')).getAttribute('aria-label') ?? '';
    // The label still begins with the "Actions for " stem so a screen reader
    // announces the control's purpose before the per-row context.
    expect(label.startsWith('Actions for ')).toBe(true);
  });

  it('includes only the entry name, not the full path', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [f1] }));

    const label = menuBtnOf(actionsOf(results, 'report.pdf')).getAttribute('aria-label') ?? '';
    expect(label).not.toContain('/');
    expect(label).not.toContain('docs');
  });

  it('interpolates the entry name verbatim (names with spaces/parens are not mangled)', async () => {
    const weird = fileEntry({
      name: 'my report (final).pdf',
      path: 'docs/my report (final).pdf',
      isDirectory: false,
      size: 5,
    });
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [weird] }));

    expect(
      menuBtnOf(actionsOf(results, 'my report (final).pdf')).getAttribute('aria-label'),
    ).toBe('Actions for my report (final).pdf');
  });

  it('keeps the visible ⋮ glyph (the aria-label is not the rendered text)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [f1] }));

    const btn = menuBtnOf(actionsOf(results, 'report.pdf'));
    // U+22EE VERTICAL ELLIPSIS — unchanged visible glyph.
    expect(btn.textContent?.trim()).toBe('⋮');
    expect(btn.textContent?.trim()).toBe('\u22EE');
  });

  it('still keeps type="button", aria-haspopup="true", aria-expanded="false" (only the label changed)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [f1] }));

    const btn = menuBtnOf(actionsOf(results, 'report.pdf'));
    expect(btn.tagName).toBe('BUTTON');
    expect(btn.className).toBe('row-menu-btn');
    expect(btn.getAttribute('type')).toBe('button');
    expect(btn.getAttribute('aria-haspopup')).toBe('true');
    expect(btn.getAttribute('aria-expanded')).toBe('false');
  });

  it('re-applies the per-row label after a re-render (not a one-shot side effect)', async () => {
    const { results } = await setupCleared();
    renderBrowse(browseResult({ path: 'docs', entries: [f1] }));
    // Simulate the re-render following a Delete/Move/Copy mutation: the
    // results element is cleared and renderBrowse rebuilds the table. The
    // per-row label must be re-derived from each entry, not dropped.
    results.innerHTML = '';
    renderBrowse(browseResult({ path: 'docs', entries: [f1, f2] }));

    expect(menuBtnOf(actionsOf(results, 'report.pdf')).getAttribute('aria-label')).toBe(
      'Actions for report.pdf',
    );
    expect(menuBtnOf(actionsOf(results, 'data.csv')).getAttribute('aria-label')).toBe(
      'Actions for data.csv',
    );
  });
});

